    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'dirty-test-'));
    const dbPath = path.join(tmpDir, 'testdb');
    // Create a directory at dbPath so reading it as a file causes EISDIR
    fs.mkdirSync(dbPath);

    const db = new Dirty(dbPath);
    let errorEmitted = false;

    db.on('error', () => {
      errorEmitted = true;
      setTimeout(() => {
        rimraf(tmpDir).finally(() => done());
      }, 100);
    });

    db.on('load', () => {
      rimraf(tmpDir).finally(() => {
        done(new Error('load should not be emitted for non-ENOENT errors; mutation detected'));
      });
    });
  });
});
